public boolean isBalanced(TreeNode root) {
    if (root == null) return true;
    Map<TreeNode, Integer> heights = new HashMap<>();
    heights.put(null, 0);
    Deque<TreeNode> stack = new ArrayDeque<>();
    TreeNode curr = root, lastVisited = null;
    boolean balanced = true;
    while (curr != null || !stack.isEmpty()) {
        if (curr != null) {
            stack.push(curr);
            curr = curr.left;
        } else {
            TreeNode peekNode = stack.peek();
            if (peekNode.right != null && lastVisited != peekNode.right) {
                curr = peekNode.right;
            } else {
                stack.pop();
                int leftH = heights.getOrDefault(peekNode.left, 0);
                int rightH = heights.getOrDefault(peekNode.right, 0);
                if (Math.abs(leftH - rightH) > 1) balanced = false;
                heights.put(peekNode, 1 + Math.max(leftH, rightH));
                lastVisited = peekNode;
            }
        }
    }
    return balanced;
}

