class Solution:
    def isBalanced(self, root) -> bool:
        heights = {None: 0}
        stack = []
        curr, last_visited = root, None
        balanced = True
        while curr or stack:
            if curr:
                stack.append(curr)
                curr = curr.left
            else:
                peek = stack[-1]
                if peek.right and last_visited is not peek.right:
                    curr = peek.right
                else:
                    stack.pop()
                    lh = heights.get(peek.left, 0)
                    rh = heights.get(peek.right, 0)
                    if abs(lh - rh) > 1:
                        balanced = False
                    heights[peek] = 1 + max(lh, rh)
                    last_visited = peek
        return balanced
